import React, { createContext, useContext, useState, useCallback } from 'react';

const ToastContext = createContext(null);

const TOAST_TYPES = {
  success: {
    bg: 'bg-white/90 border-l-4 border-l-emerald-500 text-gray-800',
    icon: '🎉',
    iconBg: 'bg-emerald-50 text-emerald-600',
  },
  error: {
    bg: 'bg-white/90 border-l-4 border-l-red-500 text-gray-800',
    icon: '⚠️',
    iconBg: 'bg-red-50 text-red-600',
  },
  warning: {
    bg: 'bg-white/90 border-l-4 border-l-amber-500 text-gray-800',
    icon: '🔔',
    iconBg: 'bg-amber-50 text-amber-600',
  },
  info: {
    bg: 'bg-white/90 border-l-4 border-l-blue-500 text-gray-800',
    icon: 'ℹ️',
    iconBg: 'bg-blue-50 text-blue-600',
  },
};

export const ToastProvider = ({ children }) => {
  const [toasts, setToasts] = useState([]);

  const removeToast = useCallback((id) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  const addToast = useCallback((message, type = 'success', duration = 3500) => {
    const id = Date.now() + Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, message, type }]);

    setTimeout(() => {
      removeToast(id);
    }, duration);
  }, [removeToast]);

  const toast = {
    success: (msg, dur) => addToast(msg, 'success', dur),
    error: (msg, dur) => addToast(msg, 'error', dur),
    warning: (msg, dur) => addToast(msg, 'warning', dur),
    info: (msg, dur) => addToast(msg, 'info', dur),
  };

  return (
    <ToastContext.Provider value={{ toast }}>
      {children}
      {/* Toast Portal/Container */}
      <div className="fixed bottom-5 right-5 z-[9999] flex flex-col gap-3 max-w-sm w-full pointer-events-none">
        {toasts.map((t) => {
          const typeMeta = TOAST_TYPES[t.type] || TOAST_TYPES.success;
          return (
            <div
              key={t.id}
              className={`toast-enter flex items-center justify-between p-4 rounded-2xl shadow-xl backdrop-blur-md border border-gray-100 w-full pointer-events-auto ${typeMeta.bg}`}
              style={{ transition: 'all 0.25s ease-in-out' }}
            >
              <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-sm font-semibold ${typeMeta.iconBg}`}>
                  {typeMeta.icon}
                </div>
                <p className="text-xs font-semibold">{t.message}</p>
              </div>
              <button
                onClick={() => removeToast(t.id)}
                className="text-gray-400 hover:text-gray-600 text-sm font-bold pl-3 flex-shrink-0"
              >
                ✕
              </button>
            </div>
          );
        })}
      </div>
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const ctx = useContext(ToastContext);
  if (!ctx) {
    throw new Error('useToast must be used within ToastProvider');
  }
  return ctx.toast;
};
